template:
const std = @import("std");

pub const Shape = [[SLOT union_kw]] {
    rectangle: struct { width: f32, height: f32 },
    circle: struct { radius: f32 },
    triangle: struct { base: f32, height: f32 },
};

pub fn calculateArea(shape: Shape) f32 {
    return switch (shape) {
        .rectangle => |r| [[SLOT rect_area]],
        .circle => |c| [[SLOT circle_area]],
        .triangle => |t| [[SLOT tri_area]],
    };
}
